import { Component, inject, input, computed } from '@angular/core';

import { ToastService, ToastPosition } from './toast.service';
import { cn } from './utils/cn';

@Component({
  selector: 'tolle-toaster',
  standalone: true,
  imports: [],
  template: `
    <div [class]="cn('fixed z-[100] flex flex-col gap-2 w-full max-w-[380px] p-4', positionClasses())">
      @for (toast of toastService.toasts(); track toast.id) {
        <div
          (mouseenter)="toastService.setPaused(toast.id, true)"
          (mouseleave)="toastService.setPaused(toast.id, false)"
          [class]="cn(
            'relative overflow-hidden p-4 rounded-md border shadow-lg flex items-start justify-between gap-4 transition-all duration-300',
            getVariantClasses(toast.variant)
          )"
        >
          <div class="flex gap-3">
            @if (toast.variant && icons[toast.variant]) {
              <i [class]="cn('text-lg', icons[toast.variant])"></i>
            }
            <div class="grid gap-1">
              @if (toast.title) {
                <div class="text-sm font-semibold leading-none">{{ toast.title }}</div>
              }
              <div class="text-xs opacity-90 leading-relaxed">{{ toast.description }}</div>
            </div>
          </div>
          <button (click)="toastService.remove(toast.id)" class="opacity-50 hover:opacity-100 transition-opacity">
            <i class="ri-close-line text-lg"></i>
          </button>
          <div
            class="absolute bottom-0 left-0 h-1 transition-all duration-100 ease-linear"
            [style.width.%]="(toast.remainingTime / (toast.duration || 3000)) * 100"
            [class]="getProgressClasses(toast.variant)"
          ></div>
        </div>
      }
    </div>
  `
})
export class ToastContainerComponent {
  toastService = inject(ToastService);
  position = input<ToastPosition>('bottom-right');

  icons = {
    destructive: 'ri-error-warning-line text-destructive dark:text-red-400',
    success: 'ri-checkbox-circle-line text-emerald-600 dark:text-emerald-400',
    default: 'ri-information-line text-primary'
  } as const;

  getVariantClasses(variant: string = 'default') {
    switch (variant) {
      case 'destructive':
        return 'border-destructive/50 bg-red-50 dark:bg-destructive/10 text-destructive dark:text-red-400';
      case 'success':
        return 'border-emerald-500/50 bg-emerald-50 dark:bg-emerald-500/10 text-emerald-700 dark:text-emerald-400';
      default:
        return 'bg-background text-foreground border-border';
    }
  }

  getProgressClasses(variant: string = 'default') {
    switch (variant) {
      case 'destructive':
        return 'bg-destructive dark:bg-red-400';
      case 'success':
        return 'bg-emerald-600 dark:bg-emerald-400';
      default:
        return 'bg-primary';
    }
  }

  positionClasses = computed(() => {
    const pos: Record<ToastPosition, string> = {
      'top-right': 'top-0 right-0 flex-col-reverse',
      'top-left': 'top-0 left-0 flex-col-reverse',
      'bottom-right': 'bottom-0 right-0',
      'bottom-left': 'bottom-0 left-0',
      'top-center': 'top-0 left-1/2 -translate-x-1/2 flex-col-reverse',
      'bottom-center': 'bottom-0 left-1/2 -translate-x-1/2'
    };
    return pos[this.position() as ToastPosition];
  });

  protected cn = cn;
}

/* -------------------------------------------------------------------------- */
/* 1. TAILWIND DIRECTIVES (MUST COME FIRST)                                   */
/* -------------------------------------------------------------------------- */
@tailwind base;
@tailwind components;
@tailwind utilities;

/* -------------------------------------------------------------------------- */
/* 2. THEME VARIABLES (CSS CUSTOM PROPERTIES)                                 */
/* -------------------------------------------------------------------------- */
:root {
  /* --- Core Colors --- */
  --background: 255 255 255;
  --foreground: 10 10 10;
  --card: 255 255 255;
  --card-foreground: 10 10 10;
  --popover: 255 255 255;
  --popover-foreground: 10 10 10;

  /* --- Primary Colors --- */
  --primary: 37 99 235;
  /* #2563eb in RGB */
  --primary-foreground: 255 255 255;

  /* --- Semantic Colors --- */
  --secondary: 244 244 245;
  /* #f4f4f5 in RGB */
  --secondary-foreground: 24 24 27;
  --muted: 244 244 245;
  --muted-foreground: 113 113 122;
  --accent: 244 244 245;
  --accent-foreground: 24 24 27;
  --destructive: 239 68 68;
  /* #ef4444 in RGB */
  --destructive-foreground: 250 250 250;

  /* --- UI Elements --- */
  --border: 228 228 231;
  /* #e4e4e7 in RGB */
  --input: 228 228 231;
  --ring: 96 165 250;
  /* #60a5fa in RGB - lighter blue */
  --radius: 0.5rem;

  /* --- Shadows --- */
  --shadow-sm: 0 1px 2px 0 rgba(0, 0, 0, 0.05);
  --shadow: 0 1px 3px 0 rgba(0, 0, 0, 0.1), 0 1px 2px -1px rgba(0, 0, 0, 0.1);
  --shadow-md: 0 4px 6px -1px rgba(0, 0, 0, 0.1), 0 2px 4px -2px rgba(0, 0, 0, 0.1);
  --shadow-lg: 0 10px 15px -3px rgba(0, 0, 0, 0.1), 0 4px 6px -4px rgba(0, 0, 0, 0.1);
}

/* --- Dark Mode --- */
.dark {
  --background: 9 9 11;
  /* #09090b in RGB */
  --foreground: 250 250 250;
  --card: 9 9 11;
  --card-foreground: 250 250 250;
  --popover: 9 9 11;
  --popover-foreground: 250 250 250;

  --primary: 59 130 246;
  /* #3b82f6 in RGB */
  --primary-foreground: 250 250 250;

  --secondary: 39 39 42;
  /* #27272a in RGB */
  --secondary-foreground: 250 250 250;
  --muted: 39 39 42;
  --muted-foreground: 161 161 170;
  --accent: 39 39 42;
  --accent-foreground: 250 250 250;

  --destructive: 127 29 29;
  /* #7f1d1d in RGB */
  --destructive-foreground: 254 242 242;

  --border: 39 39 42;
  --input: 39 39 42;
  --ring: 147 197 253;
  /* #93c5fd in RGB - even lighter blue */

  --shadow-sm: 0 1px 2px 0 rgba(0, 0, 0, 0.3);
  --shadow: 0 1px 3px 0 rgba(0, 0, 0, 0.3), 0 1px 2px -1px rgba(0, 0, 0, 0.3);
  --shadow-md: 0 4px 6px -1px rgba(0, 0, 0, 0.3), 0 2px 4px -2px rgba(0, 0, 0, 0.3);
}

/* -------------------------------------------------------------------------- */
/* 3. BASE STYLES                                                             */
/* -------------------------------------------------------------------------- */
/* Note: @layer base styles should be placed AFTER the @tailwind directives */
/* These will be injected into Tailwind's base layer */

/* You can also define base styles without @layer if you're having issues */
/* Just remove the @layer and use regular CSS */

/* Base text color inheritance - THIS IS KEY */
* {
  border-color: var(--border, #e4e4e7);
  scrollbar-width: thin;
  scrollbar-color: rgba(156, 163, 175, 0.3) transparent;
}

*::-webkit-scrollbar {
  width: 4px;
  height: 4px;
}

*::-webkit-scrollbar-track {
  background: transparent;
}

*::-webkit-scrollbar-thumb {
  background-color: rgba(156, 163, 175, 0.3);
  border-radius: 20px;
}

*::-webkit-scrollbar-thumb:hover {
  background-color: rgba(156, 163, 175, 0.5);
}

html {
  scroll-behavior: smooth;
}

body {
  background-color: var(--background, #ffffff);
  color: var(--foreground, #0a0a0a);
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  font-feature-settings: "rlig" 1, "calt" 1;
}

/* Links */
a {
  color: var(--primary, #2563eb);
  text-underline-offset: 4px;
}

a:hover {
  text-decoration: underline;
}

/* Remix Icons */
:where(i[class^="ri-"], i[class*=" ri-"]) {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  vertical-align: middle;
  font-size: 1.2em;
}

/* -------------------------------------------------------------------------- */
/* 5. UTILITY CLASSES                                                         */
/* -------------------------------------------------------------------------- */
@layer utilities {

  /* Animation utilities */
  .animate-in {
    animation: animate-in 0.2s ease-out;
  }

  .animate-out {
    animation: animate-out 0.2s ease-in;
  }

  @keyframes animate-in {
    from {
      opacity: 0;
      transform: translateY(2px);
    }

    to {
      opacity: 1;
      transform: translateY(0);
    }
  }

  @keyframes animate-out {
    from {
      opacity: 1;
      transform: translateY(0);
    }

    to {
      opacity: 0;
      transform: translateY(2px);
    }
  }

  /* Sheet Animations */
  @keyframes slide-in-from-top {
    from {
      transform: translateY(-100%);
    }

    to {
      transform: translateY(0);
    }
  }

  @keyframes slide-in-from-bottom {
    from {
      transform: translateY(100%);
    }

    to {
      transform: translateY(0);
    }
  }

  @keyframes slide-in-from-left {
    from {
      transform: translateX(-100%);
    }

    to {
      transform: translateX(0);
    }
  }

  @keyframes slide-in-from-right {
    from {
      transform: translateX(100%);
    }

    to {
      transform: translateX(0);
    }
  }

  @keyframes slide-out-to-top {
    from {
      transform: translateY(0);
    }

    to {
      transform: translateY(-100%);
    }
  }

  @keyframes slide-out-to-bottom {
    from {
      transform: translateY(0);
    }

    to {
      transform: translateY(100%);
    }
  }

  @keyframes slide-out-to-left {
    from {
      transform: translateX(0);
    }

    to {
      transform: translateX(-100%);
    }
  }

  @keyframes slide-out-to-right {
    from {
      transform: translateX(0);
    }

    to {
      transform: translateX(100%);
    }
  }

  .slide-in-from-top {
    animation: slide-in-from-top 0.3s ease-out;
  }

  .slide-in-from-bottom {
    animation: slide-in-from-bottom 0.3s ease-out;
  }

  .slide-in-from-left {
    animation: slide-in-from-left 0.3s ease-out;
  }

  .slide-in-from-right {
    animation: slide-in-from-right 0.3s ease-out;
  }

  .slide-out-to-top {
    animation: slide-out-to-top 0.3s ease-in;
  }

  .slide-out-to-bottom {
    animation: slide-out-to-bottom 0.3s ease-in;
  }

  .slide-out-to-left {
    animation: slide-out-to-left 0.3s ease-in;
  }

  .slide-out-to-right {
    animation: slide-out-to-right 0.3s ease-in;
  }

  /* Hide scrollbar */
  .no-scrollbar::-webkit-scrollbar {
    display: none;
  }

  .no-scrollbar {
    -ms-overflow-style: none;
    scrollbar-width: none;
  }

  /* Text utilities */
  .text-balance {
    text-wrap: balance;
  }

  /* Glass effect */
  .glass {
    backdrop-filter: blur(8px);
    background-color: rgba(255, 255, 255, 0.1);
    border: 1px solid rgba(255, 255, 255, 0.2);
  }

  .dark .glass {
    background-color: rgba(0, 0, 0, 0.2);
    border: 1px solid rgba(255, 255, 255, 0.1);
  }
}

/* Remove default browser focus styles */
tolle-textarea textarea:focus {
  outline: none !important;
}

tolle-select button:focus {
  outline: none !important;
}

/* -------------------------------------------------------------------------- */
/* 5. CDK OVERLAY & MODAL SYSTEM (Structural)                                 */
/* -------------------------------------------------------------------------- */
.cdk-overlay-container {
  position: fixed;
  z-index: 100;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  pointer-events: none;
}

.cdk-global-overlay-wrapper {
  display: flex;
  position: absolute;
  z-index: 1001;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  pointer-events: none;
}

.cdk-overlay-pane {
  position: absolute;
  pointer-events: auto;
  box-sizing: border-box;
  z-index: 1001;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
}

/* Backdrop Styles */
.cdk-overlay-backdrop {
  position: absolute;
  top: 0;
  bottom: 0;
  left: 0;
  right: 0;
  z-index: 1000;
  pointer-events: auto;
  -webkit-tap-highlight-color: transparent;
  transition: opacity 400ms cubic-bezier(0.25, 0.8, 0.25, 1);
  opacity: 0;
}

.cdk-overlay-backdrop-showing {
  opacity: 1;
}

.tolle-modal-backdrop {
  background-color: rgba(0, 0, 0, 0.8);
  backdrop-filter: blur(4px);
  z-index: 50;
}

/* Add these to your theme.css file */

/* Override Tailwind's default ring widths for thicker rings */
.ring-2 {
  --tw-ring-width: 3px !important;
}

.ring-4 {
  --tw-ring-width: 5px !important;
}

/* Custom ring utilities */
.ring-thick {
  --tw-ring-width: 3px !important;
}

.ring-thicker {
  --tw-ring-width: 4px !important;
}

/* Input-specific focus styles */
tolle-input:focus-within {
  --tw-ring-width: 3px;
}

/* Make sure the ring color uses our CSS variable */
.ring-ring {
  --tw-ring-color: var(--ring) !important;
}

/* Error state ring color */
.ring-destructive {
  --tw-ring-color: var(--destructive) !important;
}

/* In your global styles.css or tailwind.config.js if using Tailwind */
.rounded-sm {
  border-radius: var(--radius-sm, 0.125rem);
}

.rounded {
  border-radius: var(--radius, 0.25rem);
}

.rounded-md {
  border-radius: var(--radius-md, 0.375rem);
}

.rounded-lg {
  border-radius: var(--radius-lg, 0.5rem);
}

.rounded-xl {
  border-radius: var(--radius-xl, 0.75rem);
}

.rounded-2xl {
  border-radius: var(--radius-2xl, 1rem);
}

.rounded-3xl {
  border-radius: var(--radius-3xl, 1.5rem);
}

.rounded-full {
  border-radius: var(--radius-full, 9999px);
}

// tolle-preset.js
module.exports = {
  darkMode: 'class',
  theme: {
    extend: {
      colors: {
        // CSS Variables with RGB values
        border: 'rgb(var(--border) / <alpha-value>)',
        input: 'rgb(var(--input) / <alpha-value>)',
        ring: 'rgb(var(--ring) / <alpha-value>)',
        background: 'rgb(var(--background) / <alpha-value>)',
        foreground: 'rgb(var(--foreground) / <alpha-value>)',

        // Primary colors with opacity support
        primary: {
          DEFAULT: 'rgb(var(--primary) / <alpha-value>)',
          foreground: 'rgb(var(--primary-foreground) / <alpha-value>)',
